  if ($rc.ReturnValue -eq 4096) { if ((Wait-Job2 $rc.Job) -ne 7) { throw 'create job failed' } } elseif ($rc.ReturnValue -ne 0) { throw "create rv=$($rc.ReturnValue)" }
  $beforeMax = Read-MaxInternalSize $ims $vhdPath

