    # 1) GetVtl2Settings(VmId IN) -> Settings(uint8[] OUT), CurrentUpdateId(uint64 OUT)
    #    A non-OpenHCL virtual machine returns rv=32795 (no VTL2/paravisor configuration), Settings=null.
    $g = $gms.GetVtl2Settings($vmId)
